var surah036 = {
  number: 36,
  nameArabic: "Yasin",
  nameEnglish: "Ya-Sin",
  meaning: "Ya-Sin",
  totalAyahs: 83,
  ayahs: [
    { number: 1, arabic: "يسٓ", transliteration: "Yaseen", transliterationB: "Yaa-Seeen", english: "Ya Sin", romanUrdu: "Yasin" },
    { number: 2, arabic: "وَٱلْقُرْءَانِ ٱلْحَكِيمِ", transliteration: "Waalqurani alhakeemi", transliterationB: "Wal-Qur-aanil-Hakeem", english: "By the Qur'an, full of Wisdom", romanUrdu: "Kasam hai Quran e Hakeem ki" },
    { number: 3, arabic: "إِنَّكَ لَمِنَ ٱلْمُرْسَلِينَ", transliteration: "Innaka lamina almursaleena", transliterationB: "Innaka laminal mursaleen", english: "Thou art indeed one of the messengers", romanUrdu: "Ke tum yaqeenan Rasoolon mein se ho" },
    { number: 4, arabic: "عَلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", transliteration: "AAala siratin mustaqeemin", transliterationB: "Alaa Siraatim Mustaqeem", english: "On a Straight Way", romanUrdu: "Seedhey raastey par ho" },
    { number: 5, arabic: "تَنزِيلَ ٱلْعَزِيزِ ٱلرَّحِيمِ", transliteration: "Tanzeela alAAazeezi alrraheemi", transliterationB: "Tanzeelal 'Azeezir Raheem", english: "It is a Revelation sent down by (Him), the Exalted in Might, Most Merciful", romanUrdu: "(Aur yeh Quran) gaalib aur Raheem hasti ka nazil karda hai" },
    { number: 6, arabic: "لِتُنذِرَ قَوْمًۭا مَّآ أُنذِرَ ءَابَآؤُهُمْ فَهُمْ غَٰفِلُونَ", transliteration: "Litunthira qawman ma onthira abaohum fahum ghafiloona", transliterationB: "Litunzira qawmam maaa unzira aabaaa'uhum fahum ghaafiloon", english: "In order that thou mayest admonish a people, whose fathers had received no admonition, and who therefore remain heedless (of the Signs of Allah)", romanUrdu: "Taa-ke tum khabardar karo ek aisi qaum ko jiske baap dada khabardar na kiye gaye thay aur is wajah se woh gaflat mein padey huey hain" },
    { number: 7, arabic: "لَقَدْ حَقَّ ٱلْقَوْلُ عَلَىٰٓ أَكْثَرِهِمْ فَهُمْ لَا يُؤْمِنُونَ", transliteration: "Laqad haqqa alqawlu AAala aktharihim fahum la yuminoona", transliterationB: "Laqad haqqal qawlu 'alaaa aksarihim fahum laa yu'minoon", english: "The Word is proved true against the greater part of them: for they do not believe", romanUrdu: "Inmein se aksar log faisla-e-azaab ke mustahiq ho chuke hain, isi liye woh iman nahin latey" },
    { number: 8, arabic: "إِنَّا جَعَلْنَا فِىٓ أَعْنَٰقِهِمْ أَغْلَٰلًۭا فَهِىَ إِلَى ٱلْأَذْقَانِ فَهُم مُّقْمَحُونَ", transliteration: "Inna jaAAalna fee aAAnaqihim aghlalan fahiya ila alathqani fahum muqmahoona", transliterationB: "Innaa ja'alnaa feee a'naaqihim aghlaalan fahiya ilal azqaani fahum muqmahoon", english: "We have put yokes round their necks right up to their chins, so that their heads are forced up (and they cannot see)", romanUrdu: "Humne unki gardano mein tauq (bedi /fetters) daal diye hain jinse woh thodiyon (chins) tak jakade gaye hain, isliye woh sar uthaye khade hain" },
    { number: 9, arabic: "وَجَعَلْنَا مِنۢ بَيْنِ أَيْدِيهِمْ سَدًّۭا وَمِنْ خَلْفِهِمْ سَدًّۭا فَأَغْشَيْنَٰهُمْ فَهُمْ لَا يُبْصِرُونَ", transliteration: "WajaAAalna min bayni aydeehim saddan wamin khalfihim saddan faaghshaynahum fahum la yubsiroona", transliterationB: "Wa ja'alnaa mim baini aydeehim saddanw-wa min khalfihim saddan fa aghshai naahum fahum laa yubsiroon", english: "And We have put a bar in front of them and a bar behind them, and further, We have covered them up; so that they cannot see", romanUrdu: "Humne ek deewar unke aagey khadi kardi hai aur ek deewar unke peechey, humne unhein dhaank diya hai, unhein ab kuch nahin soojhta" },
    { number: 10, arabic: "وَسَوَآءٌ عَلَيْهِمْ ءَأَنذَرْتَهُمْ أَمْ لَمْ تُنذِرْهُمْ لَا يُؤْمِنُونَ", transliteration: "Wasawaon AAalayhim aanthartahum am lam tunthirhum la yuminoona", transliterationB: "Wa sawaaa'un 'alaihim 'a-anzartahum am lam tunzirhum laa yu'minoon", english: "The same is it to them whether thou admonish them or thou do not admonish them: they will not believe", romanUrdu: "Unke liye yaksan hai, tum unhein khabardar karo ya na karo, yeh na maanengey" },
    { number: 11, arabic: "إِنَّمَا تُنذِرُ مَنِ ٱتَّبَعَ ٱلذِّكْرَ وَخَشِىَ ٱلرَّحْمَٰنَ بِٱلْغَيْبِ ۖ فَبَشِّرْهُ بِمَغْفِرَةٍۢ وَأَجْرٍۢ كَرِيمٍ", transliteration: "Innama tunthiru mani ittabaAAa alththikra wakhashiya alrrahmana bialghaybi fabashshirhu bimaghfiratin waajrin kareemin", transliterationB: "Innamaa tunziru manit taba 'az-Zikra wa khashiyar Rahmaana bilghaib, fabashshirhu bimaghfiratinw-wa ajrin kareem", english: "Thou canst but admonish such a one as follows the Message and fears the (Lord) Most Gracious, unseen: give such a one, therefore, good tidings, of Forgiveness and a Reward most generous", romanUrdu: "Tum to usi shaks ko khabardar kar sakte ho jo naseehat ki pairvi karey aur bay-dekhe khuda e rehman se darey, usey magfirat aur ajr-e-karim ki basharat (khush khabri) de do" },
    { number: 12, arabic: "إِنَّا نَحْنُ نُحْىِ ٱلْمَوْتَىٰ وَنَكْتُبُ مَا قَدَّمُوا۟ وَءَاثَٰرَهُمْ ۚ وَكُلَّ شَىْءٍ أَحْصَيْنَٰهُ فِىٓ إِمَامٍۢ مُّبِينٍۢ", transliteration: "Inna nahnu nuhyee almawta wanaktubu ma qaddamoo waatharahum wakulla shayin ahsaynahu fee imamin mubeenin", transliterationB: "Innaa Nahnu nuhyil mawtaa wa naktubu maa qaddamoo wa aasaarahum; wa kulla shai'in ahsainaahu feee Imaamim Mubeen", english: "Verily We shall give life to the dead, and We record that which they send before and that which they leave behind, and of all things have We taken account in a clear Book (of evidence)", romanUrdu: "Hum yaqeenan ek roz murdon ko zinda karne waley hain jo kuch afaal (aamal) unhon ne kiye hain woh sab hum likhte rahey hain, aur jo kuch aasaar unhon ne peechey chodhey hain woh bhi hum sabt (likh) rahey hain. Har cheez ko humne ek khuli kitaab mein darj kar rakkha hai" },
    { number: 13, arabic: "وَٱضْرِبْ لَهُم مَّثَلًا أَصْحَٰبَ ٱلْقَرْيَةِ إِذْ جَآءَهَا ٱلْمُرْسَلُونَ", transliteration: "Waidrib lahum mathalan ashaba alqaryati ith jaaha almursaloona", transliterationB: "Wadrib lahum masalan Ashaabal Qaryatih; iz jaaa'ahal mursaloon", english: "Set forth to them, by way of a parable, the (story of) the Companions of the City. Behold!, there came messengers to it", romanUrdu: "Inhein misaal ke taur par us basti walon ka qissa sunao jabke usmein Rasool aaye thay" },
    { number: 14, arabic: "إِذْ أَرْسَلْنَآ إِلَيْهِمُ ٱثْنَيْنِ فَكَذَّبُوهُمَا فَعَزَّزْنَا بِثَالِثٍۢ فَقَالُوٓا۟ إِنَّآ إِلَيْكُم مُّرْسَلُونَ", transliteration: "Ith arsalna ilayhimu ithnayni fakaththaboohuma faAAazzazna bithalithin faqaloo inna ilaykum mursaloona", transliterationB: "Iz arsalnaaa ilaihimusnaini fakazzaboohumaa fa'azzaznaa bisaalisin faqaalooo innaaa ilaikum mursaloon", english: "When We (first) sent to them two messengers, they rejected them: But We strengthened them with a third: they said, \"Truly, we have been sent on a mission to you", romanUrdu: "Humne unki taraf do Rasool bheje aur unhon ne dono ko jhutla diya phir humne teesra madad ke liye bheja aur unsab ne kaha “Hum tumhari taraf Rasool ki haisiyat se bheje gaye hain”" },
    { number: 15, arabic: "قَالُوا۟ مَآ أَنتُمْ إِلَّا بَشَرٌۭ مِّثْلُنَا وَمَآ أَنزَلَ ٱلرَّحْمَٰنُ مِن شَىْءٍ إِنْ أَنتُمْ إِلَّا تَكْذِبُونَ", transliteration: "Qaloo ma antum illa basharun mithluna wama anzala alrrahmanu min shayin in antum illa takthiboona", transliterationB: "Qaaloo maaa antum illaa basharum mislunaa wa maaa anzalar Rahmaanu min shai'in in antum illaa takziboon", english: "The (people) said: \"Ye are only men like ourselves; and (Allah) Most Gracious sends no sort of revelation: ye do nothing but lie", romanUrdu: "Basti walon ne kaha “ tum kuch nahin ho magar hum jaise chandh Insaan, aur khuda e rehman ne hargiz koi cheez nazil nahin ki hai, tum mehaz jhoot boltey ho.”" },
    { number: 16, arabic: "قَالُوا۟ رَبُّنَا يَعْلَمُ إِنَّآ إِلَيْكُمْ لَمُرْسَلُونَ", transliteration: "Qaloo rabbuna yaAAlamu inna ilaykum lamursaloona", transliterationB: "Qaaloo Rabbunaa ya'lamu innaaa ilaikum lamursaloon", english: "They said: \"Our Lord doth know that we have been sent on a mission to you", romanUrdu: "Rasoolon ne kaha “ hamara Rubb jaanta hai ke hum zarooor tumhari taraf Rasool bana kar bheje gaye hain" },
    { number: 17, arabic: "وَمَا عَلَيْنَآ إِلَّا ٱلْبَلَٰغُ ٱلْمُبِينُ", transliteration: "Wama AAalayna illa albalaghu almubeenu", transliterationB: "Wa maa 'alainaaa illal balaaghul mubeen", english: "And our duty is only to proclaim the clear Message", romanUrdu: "Aur humpar saaf saaf paigham pahuncha dene ke siwa koi zimmedari nahin hai”" },
    { number: 18, arabic: "قَالُوٓا۟ إِنَّا تَطَيَّرْنَا بِكُمْ ۖ لَئِن لَّمْ تَنتَهُوا۟ لَنَرْجُمَنَّكُمْ وَلَيَمَسَّنَّكُم مِّنَّا عَذَابٌ أَلِيمٌۭ", transliteration: "Qaloo inna tatayyarna bikum lain lam tantahoo lanarjumannakum walayamassannakum minna AAathabun aleemun", transliterationB: "Qaaloo innaa tataiyarnaa bikum la'il-lam tantahoo lanar jumannakum wa la-yamassan nakum minnaa 'azaabun aleem", english: "The (people) said: \"for us, we augur an evil omen from you: if ye desist not, we will certainly stone you. And a grievous punishment indeed will be inflicted on you by us", romanUrdu: "Basti waley kehne lagey “hum to tumhein apne liye faal-e-badd (manhoos) samajhte hain , agar tum baaz na aaye to hum tumko sangsaar(stoning) kar dengey aur humse tum badi dardnaak saza paogey”" },
    { number: 19, arabic: "قَالُوا۟ طَٰٓئِرُكُم مَّعَكُمْ ۚ أَئِن ذُكِّرْتُم ۚ بَلْ أَنتُمْ قَوْمٌۭ مُّسْرِفُونَ", transliteration: "Qaloo tairukum maAAakum ain thukkirtum bal antum qawmun musrifoona", transliterationB: "Qaaloo taaa'irukum ma'akum; a'in zukkirtum; bal antum qawmum musrifoon", english: "They said: \"Your evil omens are with yourselves: (deem ye this an evil omen). If ye are admonished? Nay, but ye are a people transgressing all bounds", romanUrdu: "Rasoolon ne jawab diya “tumhari faal-e-badd (nahusat) to tumhare apne saath lagi hui hai , kya yeh baatein tum isliye karte ho ke tumhein naseehat ki gayi? Asal baat yeh hai ke tum hadd se guzre huey log ho”" },
    { number: 20, arabic: "وَجَآءَ مِنْ أَقْصَا ٱلْمَدِينَةِ رَجُلٌۭ يَسْعَىٰ قَالَ يَٰقَوْمِ ٱتَّبِعُوا۟ ٱلْمُرْسَلِينَ", transliteration: "Wajaa min aqsa almadeenati rajulun yasAAa qala ya qawmi ittabiAAoo almursaleena", transliterationB: "Wa jaaa'a min aqsal madeenati rajuluny yas'aa qaala yaa qawmit tabi'ul mursaleen", english: "Then there came running, from the farthest part of the City, a man, saying, \"O my people! Obey the messengers", romanUrdu: "Itne mein shehar ke door daraaz goshey se ek shaks daudta hua aaya aur bola “Aey meri qaum ke logon, Rasoolon ki pairwi ikhtiyar karlo" },
    { number: 21, arabic: "ٱتَّبِعُوا۟ مَن لَّا يَسْـَٔلُكُمْ أَجْرًۭا وَهُم مُّهْتَدُونَ", transliteration: "IttabiAAoo man la yasalukum ajran wahum muhtadoona", transliterationB: "Ittabi'oo mal-laa yas'alukum ajranw-wa hum muhtadoon", english: "Obey those who ask no reward of you (for themselves), and who have themselves received Guidance", romanUrdu: "Pairwi karo un logon ki jo tumse koi ajar nahin chahte aur theek raaste par hain" },
    { number: 22, arabic: "وَمَا لِىَ لَآ أَعْبُدُ ٱلَّذِى فَطَرَنِى وَإِلَيْهِ تُرْجَعُونَ", transliteration: "Wama liya la aAAbudu allathee fataranee wailayhi turjaAAoona", transliterationB: "Wa maa liya laaa a'budul lazee fataranee wa ilaihi turja'oon", english: "It would not be reasonable in me if I did not serve Him Who created me, and to Whom ye shall (all) be brought back", romanUrdu: "Aakhir kyun na main us hasti ki bandagi karoon jisne mujhey paida kiya hai aur jiski taraf tum sabko palat kar jana hai" },
    { number: 23, arabic: "ءَأَتَّخِذُ مِن دُونِهِۦٓ ءَالِهَةً إِن يُرِدْنِ ٱلرَّحْمَٰنُ بِضُرٍّۢ لَّا تُغْنِ عَنِّى شَفَٰعَتُهُمْ شَيْـًۭٔا وَلَا يُنقِذُونِ", transliteration: "Aattakhithu min doonihi alihatan in yuridni alrrahmanu bidurrin la tughni AAannee shafaAAatuhum shayan wala yunqithooni", transliterationB: "A-attakhizu min dooniheee aalihatan iny-yuridnir Rahmaanu bidurril-laa tughni 'annee shafaa 'atuhum shai 'anw-wa laa yunqizoon", english: "Shall I take (other) gods besides Him? If (Allah) Most Gracious should intend some adversity for me, of no use whatever will be their intercession for me, nor can they deliver me", romanUrdu: "Kya main usey chodh kar dusre ko mabood bana loon? Halaanke agar khuda e Rehman mujhey koi nuksaan pahunchana chahe to na unki shafaat mere kisi kaam aa sakti hai aur na woh mujhey chuda hi sakte hain" },
    { number: 24, arabic: "إِنِّىٓ إِذًۭا لَّفِى ضَلَٰلٍۢ مُّبِينٍ", transliteration: "Innee ithan lafee dalalin mubeenin", transliterationB: "Inneee izal-lafee dalaa-lim-mubeen", english: "I would indeed, if I were to do so, be in manifest Error", romanUrdu: "Agar main aisa karoon to main sareeh gumraahi mein mubtala ho jaunga" },
    { number: 25, arabic: "إِنِّىٓ ءَامَنتُ بِرَبِّكُمْ فَٱسْمَعُونِ", transliteration: "Innee amantu birabbikum faismaAAooni", transliterationB: "Inneee aamantu bi Rabbikum fasma'oon", english: "For me, I have faith in the Lord of you (all): listen, then, to me", romanUrdu: "Main to tumhare Rubb par iman le aaya, tum bhi meri baat maan lo.”" },
    { number: 26, arabic: "قِيلَ ٱدْخُلِ ٱلْجَنَّةَ ۖ قَالَ يَٰلَيْتَ قَوْمِى يَعْلَمُونَ", transliteration: "Qeela odkhuli aljannata qala ya layta qawmee yaAAlamoona", transliterationB: "Qeelad khulil Jannnah; qaala yaa laita qawmee ya'lamoon", english: "It was said: \"Enter thou the Garden.\" He said: \"Ah me! Would that my People knew (what I know)", romanUrdu: "(aakhir e kaar un logon ne usey qatal kardiya aur) us shaks se kehdiya gaya ke “daakhil ho ja jannat mein” usne kaha “kaash meri qaum ko maaloom hota" },
    { number: 27, arabic: "بِمَا غَفَرَ لِى رَبِّى وَجَعَلَنِى مِنَ ٱلْمُكْرَمِينَ", transliteration: "Bima ghafara lee rabbee wajaAAalanee mina almukrameena", transliterationB: "Bimaa ghafara lee Rabbee wa ja'alanee minal mukrameen", english: "For that my Lord has granted me Forgiveness and has enrolled me among those held in honour", romanUrdu: "Ke mere Rubb ne kis cheez ki badaulat meri magfirat farma di aur mujhey ba-izzat logon mein daakhil farmaya”" },
    { number: 28, arabic: "۞ وَمَآ أَنزَلْنَا عَلَىٰ قَوْمِهِۦ مِنۢ بَعْدِهِۦ مِن جُندٍۢ مِّنَ ٱلسَّمَآءِ وَمَا كُنَّا مُنزِلِينَ", transliteration: "Wama anzalna AAala qawmihi min baAAdihi min jundin mina alssamai wama kunna munzileena", transliterationB: "Wa maaa anzalnaa 'alaa qawmihee mim ba'dihee min jundim minas-samaaa'i wa maa kunnaa munzileen", english: "And We sent not down against his People, after him, any hosts from heaven, nor was it needful for Us so to do", romanUrdu: "Iske baad uski qaum par humne aasmaan se koi lashkar nahin utara , humein lashkar bhejne ki koi haajat na thi" },
    { number: 29, arabic: "إِن كَانَتْ إِلَّا صَيْحَةًۭ وَٰحِدَةًۭ فَإِذَا هُمْ خَٰمِدُونَ", transliteration: "In kanat illa sayhatan wahidatan faitha hum khamidoona", transliterationB: "In kaanat illaa saihatanw waahidatan fa-izaa hum khaamidoon", english: "It was no more than a single mighty Blast, and behold! they were (like ashes) quenched and silent", romanUrdu: "Bas ek dhamaka hua aur yakayak woh sab bujh kar reh gaye" },
    { number: 30, arabic: "يَٰحَسْرَةً عَلَى ٱلْعِبَادِ ۚ مَا يَأْتِيهِم مِّن رَّسُولٍ إِلَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ", transliteration: "Ya hasratan AAala alAAibadi ma yateehim min rasoolin illa kanoo bihi yastahzioona", transliterationB: "Yaa hasratan 'alal 'ibaad; maa yaateehim mir Rasoolin illaa kaanoo bihee yastahzi 'oon", english: "Ah! Alas for (My) Servants! There comes not a messenger to them but they mock him", romanUrdu: "Afsos bandon ke haal par, jo Rasool bhi unke paas aaya uska woh mazaaq hi udatey rahey" },
    { number: 31, arabic: "أَلَمْ يَرَوْا۟ كَمْ أَهْلَكْنَا قَبْلَهُم مِّنَ ٱلْقُرُونِ أَنَّهُمْ إِلَيْهِمْ لَا يَرْجِعُونَ", transliteration: "Alam yaraw kam ahlakna qablahum mina alqurooni annahum ilayhim la yarjiAAoona", transliterationB: "Alam yaraw kam ahlak naa qablahum minal qurooni annahum ilaihim laa yarji'oon", english: "See they not how many generations before them we destroyed? Not to them will they return", romanUrdu: "Kya unhon ne dekha nahin ke unsey pehle kitni hi qaumon ko hum halaak kar chuke hain aur iske baad woh phir kabhi unki taraf palat kar na aaye" },
    { number: 32, arabic: "وَإِن كُلٌّۭ لَّمَّا جَمِيعٌۭ لَّدَيْنَا مُحْضَرُونَ", transliteration: "Wain kullun lamma jameeAAun ladayna muhdaroona", transliterationB: "Wa in kullul lammaa jamee'ul-ladainaa muhdaroon", english: "But each one of them all - will be brought before Us (for judgment)", romanUrdu: "Un sab ko ek roz hamare saamne haazir kiya jaana hai" },
    { number: 33, arabic: "وَءَايَةٌۭ لَّهُمُ ٱلْأَرْضُ ٱلْمَيْتَةُ أَحْيَيْنَٰهَا وَأَخْرَجْنَا مِنْهَا حَبًّۭا فَمِنْهُ يَأْكُلُونَ", transliteration: "Waayatun lahumu alardu almaytatu ahyaynaha waakhrajna minha habban faminhu yakuloona", transliterationB: "Wa Aayatul lahumul ardul maitatu ahyainaahaa wa akhrajnaa minhaa habban faminhu yaakuloon", english: "A Sign for them is the earth that is dead: We do give it life, and produce grain therefrom, of which ye do eat", romanUrdu: "In logon ke liye be-jaan zameen ek nishani hai, humne isko zindagi bakshi aur issey galla (anaaj / grain) nikala jisey yeh khaate hain" },
    { number: 34, arabic: "وَجَعَلْنَا فِيهَا جَنَّٰتٍۢ مِّن نَّخِيلٍۢ وَأَعْنَٰبٍۢ وَفَجَّرْنَا فِيهَا مِنَ ٱلْعُيُونِ", transliteration: "WajaAAalna feeha jannatin min nakheelin waaAAnabin wafajjarna feeha mina alAAuyooni", transliterationB: "Wa ja'alnaa feehaa jannaatim min nakheelinw wa a'naabinw wa fajjarnaa feeha minal 'uyoon", english: "And We produce therein orchard with date-palms and vines, and We cause springs to gush forth therein", romanUrdu: "Humne ismein khajuron aur angooron ke baagh paida kiye aur uske andar chashme (springs) phodh nikale" },
    { number: 35, arabic: "لِيَأْكُلُوا۟ مِن ثَمَرِهِۦ وَمَا عَمِلَتْهُ أَيْدِيهِمْ ۖ أَفَلَا يَشْكُرُونَ", transliteration: "Liyakuloo min thamarihi wama AAamilathu aydeehim afala yashkuroona", transliterationB: "Liyaakuloo min samarihee wa maa 'amilat-hu aideehim; afalaa yashkuroon", english: "That they may enjoy the fruits of this (artistry): It was not their hands that made this: will they not then give thanks", romanUrdu: "Taa-ke yeh uske phal khayein, yeh sab kuch inke apne haathon ka paida kiya hua nahin hai phir kya yeh shukar ada nahin karte" },
    { number: 36, arabic: "سُبْحَٰنَ ٱلَّذِى خَلَقَ ٱلْأَزْوَٰجَ كُلَّهَا مِمَّا تُنۢبِتُ ٱلْأَرْضُ وَمِنْ أَنفُسِهِمْ وَمِمَّا لَا يَعْلَمُونَ", transliteration: "Subhana allathee khalaqa alazwaja kullaha mimma tunbitu alardu wamin anfusihim wamimma la yaAAlamoona", transliterationB: "Subhaanal lazee khalaqal azwaaja kullahaa mimmaa tumbitul ardu wa min anfusihim wa mimmaa laa ya'lamoon", english: "Glory to Allah, Who created in pairs all things that the earth produces, as well as their own (human) kind and (other) things of which they have no knowledge", romanUrdu: "Paak hai woh zaat jisne jumla aqsaam ke joday paida kiye khwah woh zameen ki nabataat mein se hon ya khud inki apni jins (yani naw-e-Insani) mein se ya un ashyah mein se jinko yeh jaante tak nahin hain" },
    { number: 37, arabic: "وَءَايَةٌۭ لَّهُمُ ٱلَّيْلُ نَسْلَخُ مِنْهُ ٱلنَّهَارَ فَإِذَا هُم مُّظْلِمُونَ", transliteration: "Waayatun lahumu allaylu naslakhu minhu alnnahara faitha hum muthlimoona", transliterationB: "Wa Aayatul lahumul lailu naslakhu minhun nahaara fa-izaa hum muzlimoon", english: "And a Sign for them is the Night: We withdraw therefrom the Day, and behold they are plunged in darkness", romanUrdu: "Inke liye ek aur nishani raat hai, hum uske upar se din hata dete hain to inpar andhera chaa jata hai" },
    { number: 38, arabic: "وَٱلشَّمْسُ تَجْرِى لِمُسْتَقَرٍّۢ لَّهَا ۚ ذَٰلِكَ تَقْدِيرُ ٱلْعَزِيزِ ٱلْعَلِيمِ", transliteration: "Waalshshamsu tajree limustaqarrin laha thalika taqdeeru alAAazeezi alAAaleemi", transliterationB: "Wash-shamsu tajree limustaqarril lahaa; zaalika taqdeerul 'Azeezil Aleem", english: "And the sun runs his course for a period determined for him: that is the decree of (Him), the Exalted in Might, the All-Knowing", romanUrdu: "Aur Suraj, woh apne thikane ki taraf chala ja raha hai, yeh zabardat aleem(All-Knowing) hasti ka bandha hua hisaab hai" },
    { number: 39, arabic: "وَٱلْقَمَرَ قَدَّرْنَٰهُ مَنَازِلَ حَتَّىٰ عَادَ كَٱلْعُرْجُونِ ٱلْقَدِيمِ", transliteration: "Waalqamara qaddarnahu manazila hatta AAada kaalAAurjooni alqadeemi", transliterationB: "Walqamara qaddarnaahu manaazila hattaa 'aada kal'ur joonil qadeem", english: "And the Moon,- We have measured for her mansions (to traverse) till she returns like the old (and withered) lower part of a date-stalk", romanUrdu: "Aur chand, uske liye humne manzilein muqarrar kardi hain yahan tak ke insey guzarta hua woh phir khajur ki sukhi shaakh (dry old branch) ke manind reh jata hai" },
    { number: 40, arabic: "لَا ٱلشَّمْسُ يَنۢبَغِى لَهَآ أَن تُدْرِكَ ٱلْقَمَرَ وَلَا ٱلَّيْلُ سَابِقُ ٱلنَّهَارِ ۚ وَكُلٌّۭ فِى فَلَكٍۢ يَسْبَحُونَ", transliteration: "La alshshamsu yanbaghee laha an tudrika alqamara wala allaylu sabiqu alnnahari wakullun fee falakin yasbahoona", transliterationB: "Lash shamsu yambaghee lahaaa an tudrikal qamara wa lal lailu saabiqun nahaar; wa kullun fee falaki yasbahoon", english: "It is not permitted to the Sun to catch up the Moon, nor can the Night outstrip the Day: Each (just) swims along in (its own) orbit (according to Law)", romanUrdu: "Na Suraj ke bas mein yeh hai ke woh chand ko ja pakde aur na raat din par sabqat le ja sakti hai. Sab ek ek falak mein tair rahey hain" },
    { number: 41, arabic: "وَءَايَةٌۭ لَّهُمْ أَنَّا حَمَلْنَا ذُرِّيَّتَهُمْ فِى ٱلْفُلْكِ ٱلْمَشْحُونِ", transliteration: "Waayatun lahum anna hamalna thurriyyatahum fee alfulki almashhooni", transliterationB: "Wa Aayatul lahum annaa hamalnaa zurriyatahum fil fulkil mashhoon", english: "And a Sign for them is that We bore their race (through the Flood) in the loaded Ark", romanUrdu: "Inke liye yeh bhi ek nishani hai ke humne inki nasal ko bhari hui kashti mein sawaar kardiya" },
    { number: 42, arabic: "وَخَلَقْنَا لَهُم مِّن مِّثْلِهِۦ مَا يَرْكَبُونَ", transliteration: "Wakhalaqna lahum min mithlihi ma yarkaboona", transliterationB: "Wa khalaqnaa lahum mim-mislihee maa yarkaboon", english: "And We have created for them similar (vessels) on which they ride", romanUrdu: "Aur phir inke liye waisi hi kashtiyan aur paida ki jinpar yeh sawaar hotay hain" },
    { number: 43, arabic: "وَإِن نَّشَأْ نُغْرِقْهُمْ فَلَا صَرِيخَ لَهُمْ وَلَا هُمْ يُنقَذُونَ", transliteration: "Wain nasha nughriqhum fala sareekha lahum wala hum yunqathoona", transliterationB: "Wa in nashaa nughriqhum falaa sareekha lahum wa laa hum yunqazoon", english: "If it were Our Will, We could drown them: then would there be no helper (to hear their cry), nor could they be delivered", romanUrdu: "Hum chahein to inko garq kardein, koi inki fariyad sunne wala na ho aur kisi tarah yeh na bachaye jaa sakein" },
    { number: 44, arabic: "إِلَّا رَحْمَةًۭ مِّنَّا وَمَتَٰعًا إِلَىٰ حِينٍۢ", transliteration: "Illa rahmatan minna wamataAAan ila heenin", transliterationB: "Illaa rahmatam minnaa wa mataa'an ilaa heen", english: "Except by way of Mercy from Us, and by way of (world) convenience (to serve them) for a time", romanUrdu: "Bas hamari rehmat hi hai jo inhein paar lagati aur ek waqt e khaas tak zindagi se mutamatta (enjoyment) honay ka mauqa deti hai" },
    { number: 45, arabic: "وَإِذَا قِيلَ لَهُمُ ٱتَّقُوا۟ مَا بَيْنَ أَيْدِيكُمْ وَمَا خَلْفَكُمْ لَعَلَّكُمْ تُرْحَمُونَ", transliteration: "Waitha qeela lahumu ittaqoo ma bayna aydeekum wama khalfakum laAAallakum turhamoona", transliterationB: "Wa izaa qeela lahumuttaqoo maa baina aideekum wa maa khalfakum la'allakum turhamoon", english: "When they are told, \"Fear ye that which is before you and that which will be after you, in order that ye may receive Mercy,\" (they turn back)", romanUrdu: "In logon se jab kaha jaata hai ke bacho us anjaam se jo tumhare aagey aa raha hai aur tumhare peechey guzar chukka hai, shayad ke tumpar reham kiya jaye (to yeh suni an suni kar jatey hain)" },
    { number: 46, arabic: "وَمَا تَأْتِيهِم مِّنْ ءَايَةٍۢ مِّنْ ءَايَٰتِ رَبِّهِمْ إِلَّا كَانُوا۟ عَنْهَا مُعْرِضِينَ", transliteration: "Wama tateehim min ayatin min ayati rabbihim illa kanoo AAanha muAArideena", transliterationB: "Wa maa taateehim min aayatim min ayataati Rabbihim illaa kaanoo 'anhaa mu'rideen", english: "Not a Sign comes to them from among the Signs of their Lord, but they turn away therefrom", romanUrdu: "Inke saamne inke Rubb ki aayat(nishani) mein se jo aayat(nishani) bhi aati hai yeh iski taraf iltifaat nahin karte" },
    { number: 47, arabic: "وَإِذَا قِيلَ لَهُمْ أَنفِقُوا۟ مِمَّا رَزَقَكُمُ ٱللَّهُ قَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوٓا۟ أَنُطْعِمُ مَن لَّوْ يَشَآءُ ٱللَّهُ أَطْعَمَهُۥٓ إِنْ أَنتُمْ إِلَّا فِى ضَلَٰلٍۢ مُّبِينٍۢ", transliteration: "Waitha qeela lahum anfiqoo mimma razaqakumu Allahu qala allatheena kafaroo lillatheena amanoo anutAAimu man law yashao Allahu atAAamahu in antum illa fee dalalin mubeenin", transliterationB: "Wa izaa qeela lahum anfiqoo mimmaa razaqakumul laahu qaalal lazeena kafaroo lillazeena aamanooo anut'imu mal-law yashaaa'ul laahu at'amahooo in antum illaa fee dalaalim mubeen", english: "And when they are told, \"Spend ye of (the bounties) with which Allah has provided you,\" the Unbelievers say to those who believe: \"Shall we then feed those whom, if Allah had so willed, He would have fed, (Himself)?- Ye are in nothing but manifest error", romanUrdu: "Aur jab insey kaha jaata hai ke Allah ne jo rizq tumhein ata kiya hai usmein se kuch Allah ki raah mein bhi kharch karo to yeh log jinhon ne kufr kiya hai iman laney walon ko jawab dete hain “ kya hum unko khilayein jinhein agar Allah chahta to khud khila deta? Tum to bilkul hi behak gaye ho”" },
    { number: 48, arabic: "وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Wayaqooloona mata hatha alwaAAdu in kuntum sadiqeena", transliterationB: "Wa yaqooloona mataa haazal wa'du in kuntum saadiqeen", english: "Further, they say, \"When will this promise (come to pass), if what ye say is true", romanUrdu: "Yeh log kehte hain ke “yeh qayamat ki dhamki aakhir kab poori hogi? Batao agar tum sacche ho”" },
    { number: 49, arabic: "مَا يَنظُرُونَ إِلَّا صَيْحَةًۭ وَٰحِدَةًۭ تَأْخُذُهُمْ وَهُمْ يَخِصِّمُونَ", transliteration: "Ma yanthuroona illa sayhatan wahidatan takhuthuhum wahum yakhissimoona", transliterationB: "Maa yanzuroona illaa saihatanw waahidatan taa khuzuhum wa hum yakhissimoon", english: "They will not (have to) wait for aught but a single Blast: it will seize them while they are yet disputing among themselves", romanUrdu: "Dar-asal yeh jis cheez ki raah takk rahey hain woh bas ek dhamaka hai jo yakayak inhein ain us halat mein dhar lega jab yeh (apne dunyavi maamlaat mein) jhagad rahey hongey" },
    { number: 50, arabic: "فَلَا يَسْتَطِيعُونَ تَوْصِيَةًۭ وَلَآ إِلَىٰٓ أَهْلِهِمْ يَرْجِعُونَ", transliteration: "Fala yastateeAAoona tawsiyatan wala ila ahlihim yarjiAAoona", transliterationB: "Falaa yastatee'oona taw siyatanw-wa laaa ilaaa ahlihim yarji'oon", english: "No (chance) will they then have, by will, to dispose (of their affairs), nor to return to their own people", romanUrdu: "Aur us waqt yeh wasiyat tak na kar sakenge, na apne gharon ko palat sakenge" },
    { number: 51, arabic: "وَنُفِخَ فِى ٱلصُّورِ فَإِذَا هُم مِّنَ ٱلْأَجْدَاثِ إِلَىٰ رَبِّهِمْ يَنسِلُونَ", transliteration: "Wanufikha fee alssoori faitha hum mina alajdathi ila rabbihim yansiloona", transliterationB: "Wa nufikha fis-soori faizaa hum minal ajdaasi ilaa Rabbihim yansiloon", english: "The trumpet shall be sounded, when behold! from the sepulchres (men) will rush forth to their Lord", romanUrdu: "Phir ek soor (trumpet) phoonka jayega aur yakayak ye apne Rubb ke huzur pesh honay ke liye apni qabaron se nikal padenge" },
    { number: 52, arabic: "قَالُوا۟ يَٰوَيْلَنَا مَنۢ بَعَثَنَا مِن مَّرْقَدِنَا ۜ ۗ هَٰذَا مَا وَعَدَ ٱلرَّحْمَٰنُ وَصَدَقَ ٱلْمُرْسَلُونَ", transliteration: "Qaloo ya waylana man baAAathana min marqadina hatha ma waAAada alrrahmanu wasadaqa almursaloona", transliterationB: "Qaaloo yaa wailanaa mam ba'asanaa mim marqadinaa; haaza maa wa'adar Rahmanu wa sadaqal mursaloon", english: "They will say: \"Ah! Woe unto us! Who hath raised us up from our beds of repose?\"... (A voice will say:) \"This is what (Allah) Most Gracious had promised. And true was the word of the messengers", romanUrdu: "Ghabra kar kahenge : “Arey, yeh kisne humein hamari khwab-gaah se utha khada kiya?” Yeh wahi cheez hai jiska khuda e rehman ne wada kiya tha aur Rasoolon ki baat sacchi thi”" },
    { number: 53, arabic: "إِن كَانَتْ إِلَّا صَيْحَةًۭ وَٰحِدَةًۭ فَإِذَا هُمْ جَمِيعٌۭ لَّدَيْنَا مُحْضَرُونَ", transliteration: "In kanat illa sayhatan wahidatan faitha hum jameeAAun ladayna muhdaroona", transliterationB: "In kaanat illaa saihatanw waahidatan fa-izaa hum jamee'ul ladainaa muhdaroon", english: "It will be no more than a single Blast, when lo! they will all be brought up before Us", romanUrdu: "Ek hi zoar ki aawaz hogi aur sab ke sab hamare saamne haazir kardiye jayenge" },
    { number: 54, arabic: "فَٱلْيَوْمَ لَا تُظْلَمُ نَفْسٌۭ شَيْـًۭٔا وَلَا تُجْزَوْنَ إِلَّا مَا كُنتُمْ تَعْمَلُونَ", transliteration: "Faalyawma la tuthlamu nafsun shayan wala tujzawna illa ma kuntum taAAmaloona", transliterationB: "Fal-Yawma laa tuzlamu nafsun shai'anw-wa laa tujzawna illaa maa kuntum ta'maloon", english: "Then, on that Day, not a soul will be wronged in the least, and ye shall but be repaid the meeds of your past Deeds", romanUrdu: "Aaj kisi par zarra barabar zulm na kiya jayega aur tumhein waisa hi badla diya jayega jaise amal tum karte rahe thay" },
    { number: 55, arabic: "إِنَّ أَصْحَٰبَ ٱلْجَنَّةِ ٱلْيَوْمَ فِى شُغُلٍۢ فَٰكِهُونَ", transliteration: "Inna ashaba aljannati alyawma fee shughulin fakihoona", transliterationB: "Inna Ashaabal jannatil Yawma fee shughulin faakihoon", english: "Verily the Companions of the Garden shall that Day have joy in all that they do", romanUrdu: "Aaj jannati log mazey karne mein mashgul hain" },
    { number: 56, arabic: "هُمْ وَأَزْوَٰجُهُمْ فِى ظِلَٰلٍ عَلَى ٱلْأَرَآئِكِ مُتَّكِـُٔونَ", transliteration: "Hum waazwajuhum fee thilalin AAala alaraiki muttakioona", transliterationB: "Hum wa azwaajuhum fee zilaalin 'alal araaa'iki muttaki'oon", english: "They and their associates will be in groves of (cool) shade, reclining on Thrones (of dignity)", romanUrdu: "Woh aur unki biwiyan ghanay saayon (shades) mein hain masnadon par takiye lagaye huey" },
    { number: 57, arabic: "لَهُمْ فِيهَا فَٰكِهَةٌۭ وَلَهُم مَّا يَدَّعُونَ", transliteration: "Lahum feeha fakihatun walahum ma yaddaAAoona", transliterationB: "Lahum feehaa faakiha tunw-wa lahum maa yadda'oon", english: "(Every) fruit (enjoyment) will be there for them; they shall have whatever they call for", romanUrdu: "Har qisam ki lazeez cheezein khane peene ko unke liye wahan maujood hain, jo kuch woh talab karein unke liye haazir hai" },
    { number: 58, arabic: "سَلَٰمٌۭ قَوْلًۭا مِّن رَّبٍّۢ رَّحِيمٍۢ", transliteration: "Salamun qawlan min rabbin raheemin", transliterationB: "Salaamun qawlam mir Rabbir Raheem", english: "Peace!\" - a word (of salutation) from a Lord Most Merciful", romanUrdu: "Rubb e Raheem ki taraf se unko salaam kaha gaya hai" },
    { number: 59, arabic: "وَٱمْتَٰزُوا۟ ٱلْيَوْمَ أَيُّهَا ٱلْمُجْرِمُونَ", transliteration: "Waimtazoo alyawma ayyuha almujrimoona", transliterationB: "Wamtaazul Yawma ayyuhal mujrimoon", english: "And O ye in sin! Get ye apart this Day", romanUrdu: "Aur aey mujrimon, aaj tum chatt kar alag ho jao" },
    { number: 60, arabic: "۞ أَلَمْ أَعْهَدْ إِلَيْكُمْ يَٰبَنِىٓ ءَادَمَ أَن لَّا تَعْبُدُوا۟ ٱلشَّيْطَٰنَ ۖ إِنَّهُۥ لَكُمْ عَدُوٌّۭ مُّبِينٌۭ", transliteration: "Alam aAAhad ilaykum ya banee adama an la taAAbudoo alshshaytana innahu lakum AAaduwwun mubeenun", transliterationB: "Alam a'had ilaikum yaa Baneee Aadama al-laa ta'budush Shaitaana innahoo lakum 'aduwwum mubeen", english: "Did I not enjoin on you, O ye Children of Adam, that ye should not worship Satan; for that he was to you an enemy avowed", romanUrdu: "Adam ke bacchon, kya maine tumko hidayat na ki thai ke shaytaan ki bandagi na karo, woh tumhara khula dushman hai" },
    { number: 61, arabic: "وَأَنِ ٱعْبُدُونِى ۚ هَٰذَا صِرَٰطٌۭ مُّسْتَقِيمٌۭ", transliteration: "Waani oAAbudoonee hatha siratun mustaqeemun", transliterationB: "Wa ani'budoonee; haazaa Siraatum Mustaqeem", english: "And that ye should worship Me, (for that) this was the Straight Way", romanUrdu: "Aur meri hi bandagi karo, yeh seedha raasta hai" },
    { number: 62, arabic: "وَلَقَدْ أَضَلَّ مِنكُمْ جِبِلًّۭا كَثِيرًا ۖ أَفَلَمْ تَكُونُوا۟ تَعْقِلُونَ", transliteration: "Walaqad adalla minkum jibillan katheeran afalam takoonoo taAAqiloona", transliterationB: "Wa laqad adalla minkum jibillan kaseeraa; afalam takoonoo ta'qiloon", english: "But he did lead astray a great multitude of you. Did ye not, then, understand", romanUrdu: "Magar iske bawajood usne tum mein se ek giroh-e-kaseer (great multitude of you) ko gumraah kardiya, kya tum aqal nahin rakhte thay" },
    { number: 63, arabic: "هَٰذِهِۦ جَهَنَّمُ ٱلَّتِى كُنتُمْ تُوعَدُونَ", transliteration: "Hathihi jahannamu allatee kuntum tooAAadoona", transliterationB: "Haazihee Jahannamul latee kuntum too'adoon", english: "This is the Hell of which ye were (repeatedly) warned", romanUrdu: "Yeh wahi jahannum hai jissey tumko daraya jata raha tha" },
    { number: 64, arabic: "ٱصْلَوْهَا ٱلْيَوْمَ بِمَا كُنتُمْ تَكْفُرُونَ", transliteration: "Islawha alyawma bima kuntum takfuroona", transliterationB: "Islawhal Yawma bimaa kuntum takfuroon", english: "Embrace ye the (fire) this Day, for that ye (persistently) rejected (Truth)", romanUrdu: "Jo kufr tum duniya mein karte rahey ho uski padaish mein ab iska indhan (fuel) bano" },
    { number: 65, arabic: "ٱلْيَوْمَ نَخْتِمُ عَلَىٰٓ أَفْوَٰهِهِمْ وَتُكَلِّمُنَآ أَيْدِيهِمْ وَتَشْهَدُ أَرْجُلُهُم بِمَا كَانُوا۟ يَكْسِبُونَ", transliteration: "Alyawma nakhtimu AAala afwahihim watukallimuna aydeehim watashhadu arjuluhum bima kanoo yaksiboona", transliterationB: "Al-Yawma nakhtimu 'alaaa afwaahihim wa tukallimunaaa aideehim wa tashhadu arjuluhum bimaa kaanoo yaksiboon", english: "That Day shall We set a seal on their mouths. But their hands will speak to us, and their feet bear witness, to all that they did", romanUrdu: "Aaj hum inke mooh bandh kiye detey hain, inke haath humse bolenge aur inke paon gawahi denge ke yeh duniya mein kya kamayi karte rahey hain" },
    { number: 66, arabic: "وَلَوْ نَشَآءُ لَطَمَسْنَا عَلَىٰٓ أَعْيُنِهِمْ فَٱسْتَبَقُوا۟ ٱلصِّرَٰطَ فَأَنَّىٰ يُبْصِرُونَ", transliteration: "Walaw nashao latamasna AAala aAAyunihim faistabaqoo alssirata faanna yubsiroona", transliterationB: "Wa law nashaaa'u lata masna 'alaaa aiyunihim fasta baqus-siraata fa-annaa yubsiroon", english: "If it had been our Will, We could surely have blotted out their eyes; then should they have run about groping for the Path, but how could they have seen", romanUrdu: "Hum chahein to inki aankhein moond dein(obliterated their eyes), phir yeh raastey ki taraf lapak kar dekhein, kahan se inhein raasta sujhayi dega" },
    { number: 67, arabic: "وَلَوْ نَشَآءُ لَمَسَخْنَٰهُمْ عَلَىٰ مَكَانَتِهِمْ فَمَا ٱسْتَطَٰعُوا۟ مُضِيًّۭا وَلَا يَرْجِعُونَ", transliteration: "Walaw nashao lamasakhnahum AAala makanatihim fama istataAAoo mudiyyan wala yarjiAAoona", transliterationB: "Wa law nashaaa'u lamasakhnaahum 'alaa makaanatihim famas-tataa'oo mudiyyanw-wa laa yarji'oon", english: "And if it had been Our Will, We could have transformed them (to remain) in their places; then should they have been unable to move about, nor could they have returned (after error)", romanUrdu: "Hum chahein to inhein inki jagah hi par is taraf maskh (transform) karke rakh dein ke yeh na aagey chal sakein na peechey palat sakein" },
    { number: 68, arabic: "وَمَن نُّعَمِّرْهُ نُنَكِّسْهُ فِى ٱلْخَلْقِ ۖ أَفَلَا يَعْقِلُونَ", transliteration: "Waman nuAAammirhu nunakkishu fee alkhalqi afala yaAAqiloona", transliterationB: "Wa man nu 'ammirhu nunakkishu fil-khalq; afalaa ya'qiloon", english: "If We grant long life to any, We cause him to be reversed in nature: Will they not then understand", romanUrdu: "Jis shaks ko hum lambi umar dete hain iski saakht ko hum ulat hi dete hain (we reverse in creation), kya (yeh halaat dekh kar) inhein aqal nahin aati" },
    { number: 69, arabic: "وَمَا عَلَّمْنَٰهُ ٱلشِّعْرَ وَمَا يَنۢبَغِى لَهُۥٓ ۚ إِنْ هُوَ إِلَّا ذِكْرٌۭ وَقُرْءَانٌۭ مُّبِينٌۭ", transliteration: "Wama AAallamnahu alshshiAAra wama yanbaghee lahu in huwa illa thikrun waquranun mubeenun", transliterationB: "Wa maa 'allamnaahush shi'ra wa maa yambaghee lah; in huwa illaa zikrunw-wa Qur-aanum mubeen", english: "We have not instructed the (Prophet) in Poetry, nor is it meet for him: this is no less than a Message and a Qur'an making things clear", romanUrdu: "Humne is (Nabi) ko sher nahin sikhaya hai aur na shayari isko zeib hi deti hai, yeh to ek naseehat hai aur saaf padhi janey wali kitaab" },
    { number: 70, arabic: "لِّيُنذِرَ مَن كَانَ حَيًّۭا وَيَحِقَّ ٱلْقَوْلُ عَلَى ٱلْكَٰفِرِينَ", transliteration: "Liyunthira man kana hayyan wayahiqqa alqawlu AAala alkafireena", transliterationB: "Liyunzira man kaana haiyanw-wa yahiqqal qawlu 'alal-kaafireen", english: "That it may give admonition to any (who are) alive, and that the charge may be proved against those who reject (Truth)", romanUrdu: "Taa-ke woh har us shaks ko khabardar karde jo zinda ho aur inkar karne walon par hujjat qayam ho jaye" },
    { number: 71, arabic: "أَوَلَمْ يَرَوْا۟ أَنَّا خَلَقْنَا لَهُم مِّمَّا عَمِلَتْ أَيْدِينَآ أَنْعَٰمًۭا فَهُمْ لَهَا مَٰلِكُونَ", transliteration: "Awalam yaraw anna khalaqna lahum mimma AAamilat aydeena anAAaman fahum laha malikoona", transliterationB: "Awalam yaraw annaa khalaqnaa lahum mimmaa 'amilat aideenaaa an'aaman fahum lahaa maalikoon", english: "See they not that it is We Who have created for them - among the things which Our hands have fashioned - cattle, which are under their dominion", romanUrdu: "Kya yeh log dekhte nahin hain ke humne apne haathon ki banayi hui cheezon mein se inke liye maweshi paida kiye aur ab yeh inke maalik hain" },
    { number: 72, arabic: "وَذَلَّلْنَٰهَا لَهُمْ فَمِنْهَا رَكُوبُهُمْ وَمِنْهَا يَأْكُلُونَ", transliteration: "Wathallalnaha lahum faminha rakoobuhum waminha yakuloona", transliterationB: "Wa zallalnaahaa lahum faminhaa rakoobuhum wa minhaa yaakuloon", english: "And that We have subjected them to their (use)? of them some do carry them and some they eat", romanUrdu: "Humne unhein is tarah inke bas mein kardiya hai ke unmein se kisi par yeh sawaar hotey hain, kisika yeh gosht khate hain" },
    { number: 73, arabic: "وَلَهُمْ فِيهَا مَنَٰفِعُ وَمَشَارِبُ ۖ أَفَلَا يَشْكُرُونَ", transliteration: "Walahum feeha manafiAAu wamasharibu afala yashkuroona", transliterationB: "Wa lahum feehaa manaa fi'u wa mashaarib; afalaa yashkuroon", english: "And they have (other) profits from them (besides), and they get (milk) to drink. Will they not then be grateful", romanUrdu: "Aur unke andar inke liye tarah tarah ke fawaid (benefits) aur mashrubaat (drinks) hain phir kya yeh shukar guzar nahin hotay" },
    { number: 74, arabic: "وَٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ ءَالِهَةًۭ لَّعَلَّهُمْ يُنصَرُونَ", transliteration: "Waittakhathoo min dooni Allahi alihatan laAAallahum yunsaroona", transliterationB: "Wattakhazoo min doonil laahi aalihatal la'allahum yunsaroon", english: "Yet they take (for worship) gods other than Allah, (hoping) that they might be helped", romanUrdu: "Yeh sabkuch hotey huey inhon ne Allah ke siwa dusre khuda bana liye hain aur yeh umeed rakhte hain ke inki madad ki jayegi" },
    { number: 75, arabic: "لَا يَسْتَطِيعُونَ نَصْرَهُمْ وَهُمْ لَهُمْ جُندٌۭ مُّحْضَرُونَ", transliteration: "La yastateeAAoona nasrahum wahum lahum jundun muhdaroona", transliterationB: "Laa yastatee'oona nasrahum wa hum lahum jundum muhdaroon", english: "They have not the power to help them: but they will be brought up (before Our Judgment-seat) as a troop (to be condemned)", romanUrdu: "Woh inki koi madad nahin kar sakte balke yeh log ultey unke liye hazir-baash lashkar (army in waiting ) baney huey hain" },
    { number: 76, arabic: "فَلَا يَحْزُنكَ قَوْلُهُمْ ۘ إِنَّا نَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَ", transliteration: "Fala yahzunka qawluhum inna naAAlamu ma yusirroona wama yuAAlinoona", transliterationB: "Falaa yahzunka qawluhum; innaa na'lamu maa yusirroona wa maa yu'linoon", english: "Let not their speech, then, grieve thee. Verily We know what they hide as well as what they disclose", romanUrdu: "Accha, jo baatein yeh bana rahey hain woh tumhein ranjeeda na karein, inki chupi aur khuli sab baaton ko hum jaante hain" },
    { number: 77, arabic: "أَوَلَمْ يَرَ ٱلْإِنسَٰنُ أَنَّا خَلَقْنَٰهُ مِن نُّطْفَةٍۢ فَإِذَا هُوَ خَصِيمٌۭ مُّبِينٌۭ", transliteration: "Awalam yara alinsanu anna khalaqnahu min nutfatin faitha huwa khaseemun mubeenun", transliterationB: "Awalam yaral insaanu annaa khalaqnaahu min nutfatin fa-izaa huwa khaseemum mubeen", english: "Doth not man see that it is We Who created him from sperm? yet behold! he (stands forth) as an open adversary", romanUrdu: "Kya Insaan dekhta nahin hai ke humne usey nutfe(sperm drop) se paida kiya aur phir woh sareeh jhagdalu bankar khada ho gaya" },
    { number: 78, arabic: "وَضَرَبَ لَنَا مَثَلًۭا وَنَسِىَ خَلْقَهُۥ ۖ قَالَ مَن يُحْىِ ٱلْعِظَٰمَ وَهِىَ رَمِيمٌۭ", transliteration: "Wadaraba lana mathalan wanasiya khalqahu qala man yuhyee alAAithama wahiya rameemun", transliterationB: "Wa daraba lanaa maslanw-wa nasiya khalqahoo qaala mai-yuhyil'izaama wa hiya rameem", english: "And he makes comparisons for Us, and forgets his own (origin and) Creation: He says, \"Who can give life to (dry) bones and decomposed ones (at that)", romanUrdu: "Ab woh humpar misalein chaspan karta hai aur apni paidaish ko bhool jaata hai , kehta hai “kaun in haddiyon ko zinda karega jabke yeh boseeda (rotten) ho chuki hon?”" },
    { number: 79, arabic: "قُلْ يُحْيِيهَا ٱلَّذِىٓ أَنشَأَهَآ أَوَّلَ مَرَّةٍۢ ۖ وَهُوَ بِكُلِّ خَلْقٍ عَلِيمٌ", transliteration: "Qul yuhyeeha allathee anshaaha awwala marratin wahuwa bikulli khalqin AAaleemun", transliterationB: "Qul yuh yeehal lazeee ansha ahaaa awwala marrah; wa Huwa bikulli khalqin 'Aleem", english: "Say, \"He will give them life Who created them for the first time! for He is Well-versed in every kind of creation", romanUrdu: "Ussey kaho,inhein wahi zinda karega jisne pehle inhein paida kiya tha, aur woh takhleeq (creation) ka har kaam jaanta hai" },
    { number: 80, arabic: "ٱلَّذِى جَعَلَ لَكُم مِّنَ ٱلشَّجَرِ ٱلْأَخْضَرِ نَارًۭا فَإِذَآ أَنتُم مِّنْهُ تُوقِدُونَ", transliteration: "Allathee jaAAala lakum mina alshshajari alakhdari naran faitha antum minhu tooqidoona", transliterationB: "Allazee ja'ala lakum minash shajaril akhdari naaran fa-izaaa antum minhu tooqidoon", english: "The same Who produces for you fire out of the green tree, when behold! ye kindle therewith (your own fires)", romanUrdu: "Wahi jisne tumhare liye harey bharey (green) darakht se aag paida kardi aur tum ussey apne chuleh (stoves) roshan karte ho" },
    { number: 81, arabic: "أَوَلَيْسَ ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِقَٰدِرٍ عَلَىٰٓ أَن يَخْلُقَ مِثْلَهُم ۚ بَلَىٰ وَهُوَ ٱلْخَلَّٰقُ ٱلْعَلِيمُ", transliteration: "Awalaysa allathee khalaqa alssamawati waalarda biqadirin AAala an yakhluqa mithlahum bala wahuwa alkhallaqu alAAaleemu", transliterationB: "Awa laisal lazee khalaqas samaawaati wal arda biqaadirin 'alaaa ai-yakhluqa mislahum; balaa wa Huwal Khallaaqul 'Aleem", english: "Is not He Who created the heavens and the earth able to create the like thereof?\" - Yea, indeed! for He is the Creator Supreme, of skill and knowledge (infinite)", romanUrdu: "Kya woh jisne aasmaano aur zameen ko paida kiya ispar qadir nahin hai ke in jaison ko paida kar sakey? Kyun nahin, jabke woh maahir khallaq (superb creator) hai" },
    { number: 82, arabic: "إِنَّمَآ أَمْرُهُۥٓ إِذَآ أَرَادَ شَيْـًٔا أَن يَقُولَ لَهُۥ كُن فَيَكُونُ", transliteration: "Innama amruhu itha arada shayan an yaqoola lahu kun fayakoonu", transliterationB: "Innamaa amruhooo izaaa araada shai'an ai-yaqoola lahoo kun fa-yakoon", english: "Verily, when He intends a thing, His Command is, \"be\", and it is", romanUrdu: "Woh to jab kisi cheez ka irada karta hai to uska kaam bas yeh hai ke usey hukum de ke hoja aur woh jo jati hai" },
    { number: 83, arabic: "فَسُبْحَٰنَ ٱلَّذِى بِيَدِهِۦ مَلَكُوتُ كُلِّ شَىْءٍۢ وَإِلَيْهِ تُرْجَعُونَ", transliteration: "Fasubhana allathee biyadihi malakootu kulli shayin wailayhi turjaAAoona", transliterationB: "Fa Subhaanal lazee biyadihee malakootu kulli shai-inw-wa ilaihi turja'oon", english: "So glory to Him in Whose hands is the dominion of all things: and to Him will ye be all brought back", romanUrdu: "Paak hai woh jiske haath mein har cheez ka mukammal iqtedar (full control) hai, aur usi ki taraf tum paltaye janey waale ho" }
  ]
};
